class ServiceMeshClient {
  private readonly http: AxiosInstance;

  constructor(
    readonly baseURL: string = process.env.SERVICE_MESH_BASE_URL ?? 'http://mesh-gateway',
    readonly timeout = 5_000,
  ) {
    this.http = axios.create({ baseURL: this.baseURL, timeout: this.timeout });
  }

  /**
   * Scale an application up/down by "factor" replicas.
   * This interacts with the platform orchestrator through
   * the mesh sidecar.
   */
  public async scale(appId: string, factor: number): Promise<void> {
    try {
      await this.http.post(`/apps/${appId}/scale`, { factor });
      console.info(`[Scale] ${appId} scaled by ${factor}`);
    } catch (err) {
      console.error(`[Scale] Failed to scale ${appId}:`, err);
    }
  }
}

/* -------------------------------------------------------------------------- */
/*                            Main Orchestrator Class                         */
/* -------------------------------------------------------------------------- */

export class SocialAwareAutoScaler {
  private readonly kafka: Kafka;
  private readonly meshClient = new ServiceMeshClient();
  private readonly eventBus = new MetricEventBus();
  private readonly strategies: ScalingStrategy[] = [];
  private readonly alertChain: AlertHandler;
  private isShuttingDown = false;

  constructor(
    private readonly kafkaBrokers: string[] = (process.env.KAFKA_BROKERS ?? 'localhost:9092').split(','),
    private readonly groupId = 'social-auto-scaler',
    private readonly topic = 'pulse.metric.enriched.v1',
  ) {
    this.kafka = new Kafka({
      clientId: 'pulse-auto-scaler',
      brokers: this.kafkaBrokers,
      logLevel: KafkaLogLevel.NOTHING,
    });

    /* Strategy registry */
    this.strategies.push(
      new HighCpuStrategy(this.meshClient),
      new SentimentSpikeStrategy(this.meshClient),
    );

    /* Alert chain bootstrap */
    const debug   = new DebugAlertHandler();
    const warn    = new WarningAlertHandler();
    const crit    = new CriticalAlertHandler();
    debug.setNext(warn).setNext(crit);
    this.alertChain = debug; // entrypoint

    /* Wiring observer */
    this.eventBus.onMetric(async (metric) => {
      await this.alertChain.handle(metric);
      await this.applyStrategies(metric);
    });
  }

  /**
   * Initialize kafka consumer & begin event pump.
   */
  public async start(): Promise<void> {
    const consumer = this.kafka.consumer({ groupId: this.groupId });
    await consumer.connect();
    await consumer.subscribe({ topic: this.topic, fromBeginning: false });

    console.info('[AutoScaler] started.');

    await consumer.run({
      eachMessage: async (payload: EachMessagePayload) => {
        if (this.isShuttingDown) {
          await consumer.disconnect();
          return;
        }
        const metric = this.parseMetric(payload);
        if (metric) this.eventBus.emitMetric(metric);
      },
    });

    /* Graceful shutdown binding */
    process.once('SIGINT' , () => this.shutdown());
    process.once('SIGTERM', () => this.shutdown());
  }

  private async applyStrategies(metric: EnrichedMetric): Promise<void> {
    for (const strategy of this.strategies) {
      const cmd = strategy.evaluate(metric);
      if (cmd) {
        try {
          await cmd.execute();
          break; // one strategy acted – avoid conflicting actions
        } catch (err) {
          console.error('[AutoScaler] Command failed:', err);
        }
      }
    }
  }

  /**
   * Converts Kafka payload into EnrichedMetric object with validation.
   */
  private parseMetric({ message }: EachMessagePayload): EnrichedMetric | undefined {
    try {
      if (!message.value) return;
      const obj = JSON.parse(message.value.toString());

      /* Lightweight validation */
      const metric: EnrichedMetric = {
        appId          : obj.appId,
        cpuPct         : Number(obj.cpuPct),
        memPct         : Number(obj.memPct),
        sentimentScore : Number(obj.sentimentScore),
        trendingScore  : Number(obj.trendingScore),
        timestamp      : Number(obj.timestamp),
      };

      if (!metric.appId || Number.isNaN(metric.cpuPct)) {
        throw new Error('Invalid metric shape');
      }
      return metric;
    } catch (err) {
      console.warn('[AutoScaler] Discarded malformed metric:', err);
      return;
    }
  }

  /**
   * Shutdown hook – ensures consumer disconnect & drains inflight tasks.
   */
  private async shutdown(): Promise<void> {
    if (this.isShuttingDown) return;
    this.isShuttingDown = true;

    console.info('[AutoScaler] Shutting down…');
    // Additional cleanup (HTTP, etc.) could be awaited here.
  }
}

/* -------------------------------------------------------------------------- */
/*                     Module bootstrap (only when run directly)              */
/* -------------------------------------------------------------------------- */
if (require.main === module) {
  (async () => {
    try {
      const scaler = new SocialAwareAutoScaler();
      await scaler.start();
    } catch (err) {
      console.error('[AutoScaler] Fatal:', err);
      process.exitCode = 1;
    }
  })();
}

/******************************************************************************************
 *  File:        src/module_33.ts
 *  Project:     PulseSphere SocialOps (system_monitoring)
 *
 *  Description:
 *  Social-Aware Auto-Scaler micro-service. Listens to infrastructure telemetry (CPU/memory)
 *  from Apache Kafka, listens to near-real-time social-interaction signals from NATS,
 *  merges the two streams and decides—via configurable Strategy pattern—whether capacity
 *  should be scaled up/down. If a scaling decision is made it emits a Command event back
 *  to the message bus. Additionally, it forwards critical alerts through the centralized
 *  NotificationService.
 *
 *  NOTE: 3rd-party SDKs are thinly wrapped to allow mocking in unit tests; production
 *  credentials and topics/subjects are injected via env-vars or Secret-Manager.
 ******************************************************************************************/

/* ================================== Imports ========================================= */

import { Kafka, Producer, EachMessagePayload } from 'kafkajs';
import { connect as natsConnect, NatsConnection, Subscription, JSONCodec } from 'nats';
import pino, { Logger } from 'pino';
import { v4 as uuid } from 'uuid';
import { notificationService, AlertMessage } from './services/notificationService';

/* ============================== Domain & Contracts ================================== */

/**
 * Represents infrastructure telemetry pulled from Prometheus-push gateway (simplified).
 */
export interface SystemMetric {
  timestamp: number;              // unix epoch ms
  instanceId: string;             // k8s node or pod id
  cpuLoadPct: number;             // e.g., 0.73 means 73%
  memoryLoadPct: number;
}

/**
 * Represents social-interaction spikes (likes, comments, shares, etc.)
 */
export interface SocialSignal {
  timestamp: number;
  campaignId?: string;
  hashtag?: string;
  deltaPerSecond: number;         // increase of interactions per sec
}

/**
 * Consolidated view that Strategies will look at.
 */
export interface CombinedMetrics {
  system: SystemMetric;
  social?: SocialSignal;
}

/**
 * Command event that goes onto Kafka for Orchestration service.
 */
export interface ScalingCommand {
  commandId: string;
  issuedAt: number;
  targetGroup: string;            // e.g., "video-processor-pods"
  action: 'SCALE_UP' | 'SCALE_DOWN';
  desiredReplicas: number;
  reason: string;
}

/* =========================== Strategy Pattern ======================================= */

export interface ScalingStrategy {
  readonly name: string;
  evaluate(input: CombinedMetrics): ScalingCommand | null;
}

/**
 * 1. Pure CPU strategy—scale if CPU surpasses threshold.
 */
export class CpuLoadStrategy implements ScalingStrategy {
  readonly name = 'CpuLoadStrategy';

  constructor(
    private readonly cpuUpperThreshold = 0.8,
    private readonly cpuLowerThreshold = 0.25,
    private readonly maxReplicas = 16,
    private readonly minReplicas = 2
  ) {}

  evaluate(input: CombinedMetrics): ScalingCommand | null {
    const { cpuLoadPct, instanceId } = input.system;
    let action: ScalingCommand['action'] | null = null;
    let desired: number | null = null;

    if (cpuLoadPct >= this.cpuUpperThreshold) {
      action = 'SCALE_UP';
      desired = Math.min(this.maxReplicas, Math.ceil(cpuLoadPct * 10));
    } else if (cpuLoadPct <= this.cpuLowerThreshold) {
      action = 'SCALE_DOWN';
      desired = Math.max(this.minReplicas, Math.floor(cpuLoadPct * 10));
    }

    if (action && desired !== null) {
      return {
        commandId: uuid(),
        issuedAt: Date.now(),
        targetGroup: instanceId,
        action,
        desiredReplicas: desired,
        reason: `CPU load ${cpuLoadPct * 100}% triggered ${action}`
      };
    }
    return null;
  }
}

/**
 * 2. Social trend strategy—scale on viral spikes regardless of current CPU.
 */
export class SocialTrendingStrategy implements ScalingStrategy {
  readonly name = 'SocialTrendingStrategy';

  constructor(
    private readonly spikeThreshold = 5000,        // interactions/sec
    private readonly surgeReplicas = 8
  ) {}

  evaluate(input: CombinedMetrics): ScalingCommand | null {
    if (!input.social) return null;
    const { deltaPerSecond, hashtag } = input.social;
    if (deltaPerSecond >= this.spikeThreshold) {
      return {
        commandId: uuid(),
        issuedAt: Date.now(),
        targetGroup: hashtag ?? 'global',
        action: 'SCALE_UP',
        desiredReplicas: this.surgeReplicas,
        reason: `Social spike (${deltaPerSecond}/s) for #${hashtag}`
      };
    }
    return null;
  }
}

/**
 * 3. Hybrid strategy—showcases Strategy composition.
 */
export class HybridStrategy implements ScalingStrategy {
  readonly name = 'HybridStrategy';
  private readonly innerStrategies: ScalingStrategy[];

  constructor(...strategies: ScalingStrategy[]) {
    this.innerStrategies = strategies;
  }

  evaluate(input: CombinedMetrics): ScalingCommand | null {
    for (const strat of this.innerStrategies) {
      const cmd = strat.evaluate(input);
      if (cmd) return cmd;
    }
    return null;
  }
}

/* ============================ Auto-Scaler Service =================================== */

export class SocialAwareAutoScaler {
  private readonly kafka: Kafka;
  private readonly kafkaProducer: Producer;
  private readonly natsConn: NatsConnection;
  private readonly jc = JSONCodec();

  private readonly logger: Logger;
  private readonly strategy: ScalingStrategy;

  constructor(
    private readonly kafkaBrokers: string[],
    private readonly natsUrl: string,
    strategy?: ScalingStrategy
  ) {
    this.logger = pino({ name: 'SocialAwareAutoScaler' });
    this.kafka = new Kafka({ clientId: 'auto-scaler', brokers: kafkaBrokers });
    this.kafkaProducer = this.kafka.producer();
    this.strategy = strategy ?? new HybridStrategy(
      new SocialTrendingStrategy(),
      new CpuLoadStrategy()
    );
    this.natsConn = {} as any; // will connect later
  }

  /* ---------- Bootstrapping ---------- */

  async start(): Promise<void> {
    try {
      await this.kafkaProducer.connect();
      this.logger.info('Kafka producer connected');

      // Connect to NATS
      this.natsConn = await natsConnect({ servers: this.natsUrl });
      this.logger.info('NATS connected');

      // Subscribe to streams
      await this.subscribeSystemMetrics();
      await this.subscribeSocialSignals();

      this.logger.info(`Auto-Scaler started with strategy ${this.strategy.name}`);
    } catch (err) {
      this.logger.fatal({ err }, 'Failed to start Auto-Scaler');
      process.exit(1);
    }
  }

  async shutdown(): Promise<void> {
    await Promise.allSettled([this.kafkaProducer.disconnect(), this.natsConn.close()]);
    this.logger.info('Graceful shutdown complete.');
  }

  /* ---------- Internal Subscription Logic ---------- */

  private async subscribeSystemMetrics(): Promise<void> {
    const consumer = this.kafka.consumer({ groupId: 'auto-scaler-group' });
    await consumer.connect();
    await consumer.subscribe({ topic: 'telemetry.system', fromBeginning: false });

    consumer.run({
      eachMessage: async (payload: EachMessagePayload) => {
        try {
          const metric: SystemMetric = JSON.parse(payload.message.value!.toString());

          // Merge with any cached social signal if available
          const combined: CombinedMetrics = { system: metric, social: this.lastSocialSignal };

          await this.maybeScale(combined);
        } catch (err) {
          this.logger.error({ err }, 'Failed to handle system metric message');
        }
      }
    });
  }

  private lastSocialSignal?: SocialSignal;
  private async subscribeSocialSignals(): Promise<void> {
    const sub: Subscription = this.natsConn.subscribe('social.trending');
    (async () => {
      for await (const msg of sub) {
        try {
          const signal: SocialSignal = this.jc.decode(msg.data);
          this.lastSocialSignal = signal; // simple cache
          const dummySystem: SystemMetric = {
            timestamp: signal.timestamp,
            instanceId: 'social-only',
            cpuLoadPct: 0,
            memoryLoadPct: 0
          };
          await this.maybeScale({ system: dummySystem, social: signal });

        } catch (err) {
          this.logger.error({ err }, 'Failed to handle social signal message');
        }
      }
    })().catch(err => this.logger.error({ err }, 'NATS subscription failed'));
  }

  /* ---------- Core Decision Loop ---------- */

  private async maybeScale(input: CombinedMetrics): Promise<void> {
    const cmd = this.strategy.evaluate(input);
    if (cmd) {
      this.logger.info({ cmd }, 'Scaling decision issued');

      try {
        await this.kafkaProducer.send({
          topic: 'orchestration.scaling.command',
          messages: [{ key: cmd.targetGroup, value: JSON.stringify(cmd) }]
        });
      } catch (err) {
        this.logger.error({ err }, 'Failed to publish scaling command');
        // Dispatch alert via NotificationService
        const alertMessage: AlertMessage = {
          severity: 'warning',
          title: 'Scaling command failed',
          details: {
            error: String(err),
            command: cmd,
          },
          sourceModule: 'module_33',
        };
        await notificationService.dispatch(alertMessage);
      }
    }
  }
}

/* ============================= Run if main ========================================== */

if (require.main === module) {
  const scaler = new SocialAwareAutoScaler(
    process.env.KAFKA_BROKERS?.split(',') ?? ['localhost:9092'],
    process.env.NATS_URL ?? 'nats://127.0.0.1:4222'
  );

  scaler.start();

  // Graceful shutdown
  process.on('SIGINT', async () => {
    await scaler.shutdown();
    process.exit(0);
  });
}

/***************************************************************************************************
 *  File:          src/module_22.ts
 *  Project:       PulseSphere SocialOps – system_monitoring
 *  Description:   Trending-event correlation + auto-scaling engine.
 *
 *  This module listens to enriched social-interaction telemetry (Kafka topic: social_metrics),
 *  detects virality events in real time, predicts the impact on infrastructure capacity and
 *  triggers remediation via a pluggable Strategy + Chain-of-Responsibility implementation.
 *  Alerts are dispatched via the centralized NotificationService.
 *
 *  Patterns showcased
 *  ────────────────────────────────────────────────────────────────────────────────────────────────
 *  • Strategy Pattern               – ScalingStrategy (HPA, Keda, CustomAutoscaler)
 *  • Chain-of-Responsibility        – RemediationHandler (Scaler → Alerting → Fallback)
 *  • Observer Pattern               – Simple EventEmitter-based listener notification
 *  • Dependency-Inversion Principle – high-level policies depend on abstractions, not concretions
 *
 *  External Deps: kafkajs, pino, node-eventemitter-3, @types/node (for timers / events)
 ***************************************************************************************************/

import { Kafka, Consumer, EachMessagePayload } from 'kafkajs';
import EventEmitter from 'events';
import pino from 'pino';
import { notificationService, AlertMessage } from './services/notificationService';

/* -------------------------------------------------------------------------- */
/*                               Shared Typings                               */
/* -------------------------------------------------------------------------- */

/**
 * Raw event emitted by Social-Interaction stream
 */
interface SocialMetricEvent {
  ts: number;                // epoch millis
  hashtag: string;           // primary hashtag detected in message
  likes: number;             // #likes within aggregation window
  comments: number;          // #comments within aggregation window
  shares: number;            // #shares within aggregation window
  viewers: number;           // concurrent live-stream viewers
}

/**
 * Calculated metadata that augments SocialMetricEvent
 */
interface CorrelatedSignal {
  viralityScore: number;     // Weighted score used to anticipate traffic surge
  projectedRPS: number;      // Predicted requests-per-second that backend will receive
}

/**
 * Result produced by a ScalingStrategy. Nullable fields are allowed when
 * strategy deems no action is necessary.
 */
interface ScalingDecision {
  /**
   * Desired replica count for target deployment (e.g., Kubernetes Deployment)
   */
  desiredReplicas: number | null;

  /**
   * Estimated cost (useful for A/B strategy benchmarking)
   */
  expectedCostUSD?: number;

  /**
   * Optional metadata describing reasoning
   */
  rationale?: string;
}

/* -------------------------------------------------------------------------- */
/*                          Logging / Observability utils                     */
/* -------------------------------------------------------------------------- */

const logger = pino({
  name: 'virality-correlator',
  level: process.env.LOG_LEVEL || 'info',
  transport:
    process.env.NODE_ENV !== 'production'
      ? { target: 'pino-pretty', options: { colorize: true } }
      : undefined,
});

/* -------------------------------------------------------------------------- */
/*                              Observer Pattern                              */
/* -------------------------------------------------------------------------- */

/**
 * Event bus for internal notifications within this micro-service
 */
class InternalBus extends EventEmitter {
  static readonly EVENTS = {
    VIRALITY_DETECTED: 'virality_detected',
    SCALE_DECISION: 'scale_decision',
    REMEDIATION_FAILED: 'remediation_failed',
  } as const;
}

const bus = new InternalBus();

/* -------------------------------------------------------------------------- */
/*                             Strategy Pattern                               */
/* -------------------------------------------------------------------------- */

/**
 * Defines contract for a capacity scaling algorithm
 */
interface ScalingStrategy {
  name: string;
  assess(signal: CorrelatedSignal): Promise<ScalingDecision>;
}

/**
 * Baseline strategy: HorizontalPodAutoscaler-like rule engine
 */
class HPAStrategy implements ScalingStrategy {
  public readonly name = 'hpa';

  constructor(
    private minReplicas: number,
    private maxReplicas: number,
    private rpsPerReplica: number,
  ) {}

  async assess(signal: CorrelatedSignal): Promise<ScalingDecision> {
    const { projectedRPS } = signal;
    const desired = Math.ceil(projectedRPS / this.rpsPerReplica);

    if (desired <= this.minReplicas) {
      return { desiredReplicas: this.minReplicas, rationale: 'Within min bounds' };
    }
    if (desired >= this.maxReplicas) {
      return {
        desiredReplicas: this.maxReplicas,
        rationale: 'Capped at max replicas',
      };
    }
    return { desiredReplicas: desired, rationale: 'Scaled linearly against RPS' };
  }
}

/**
 * Cost-aware custom strategy which chooses between spot and on-demand nodes
 */
class CostOptimizedStrategy implements ScalingStrategy {
  public readonly name = 'cost_optimized';

  constructor(private baseline: HPAStrategy, private costPerReplica: number) {}

  async assess(signal: CorrelatedSignal): Promise<ScalingDecision> {
    const base = await this.baseline.assess(signal);
    if (base.desiredReplicas === null) {
      return base;
    }
    const cost = base.desiredReplicas * this.costPerReplica;
    return {
      ...base,
      expectedCostUSD: cost,
      rationale: `${base.rationale}. Estimated cost $${cost.toFixed(2)}`,
    };
  }
}

/* -------------------------------------------------------------------------- */
/*                       Chain-of-Responsibility Pattern                       */
/* -------------------------------------------------------------------------- */

/**
 * Abstract handler capable of executing/handling remediation action
 */
abstract class RemediationHandler {
  private nextHandler: RemediationHandler | null = null;

  setNext(next: RemediationHandler): RemediationHandler {
    this.nextHandler = next;
    return next;
  }

  async handle(signal: CorrelatedSignal, decision: ScalingDecision): Promise<void> {
    try {
      const handled = await this.process(signal, decision);
      if (!handled && this.nextHandler) {
        await this.nextHandler.handle(signal, decision);
      }
    } catch (err) {
      logger.error(err, 'Remediation handler threw error');
      bus.emit(InternalBus.EVENTS.REMEDIATION_FAILED, err);
      if (this.nextHandler) {
        await this.nextHandler.handle(signal, decision);
      }
    }
  }

  protected abstract process(
    signal: CorrelatedSignal,
    decision: ScalingDecision,
  ): Promise<boolean>;
}

/**
 * First link: Perform actual scaling action via Kubernetes API
 */
class KubernetesScaler extends RemediationHandler {
  constructor(private readonly kubeClient: IKubeClient, private readonly deployment: string) {
    super();
  }

  protected async process(
    _signal: CorrelatedSignal,
    decision: ScalingDecision,
  ): Promise<boolean> {
    if (decision.desiredReplicas === null) return false;

    logger.info(
      { deployment: this.deployment, replicas: decision.desiredReplicas },
      'Scaling deployment',
    );

    // Safeguard: avoid flapping
    const current = await this.kubeClient.getReplicaCount(this.deployment);
    if (current === decision.desiredReplicas) {
      logger.debug('Desired replica count already satisfied; skipping scale action.');
      return true;
    }

    await this.kubeClient.scaleDeployment(this.deployment, decision.desiredReplicas);
    return true; // handled!
  }
}

/**
 * Second link: Send alert via NotificationService if scaling failed / not possible
 */
class AlertNotifier extends RemediationHandler {
  protected async process(
    signal: CorrelatedSignal,
    decision: ScalingDecision,
  ): Promise<boolean> {
    const severity: AlertMessage['severity'] = decision.desiredReplicas === null ? 'info' : 'warning';
    const message =
      decision.desiredReplicas === null
        ? 'No scaling required.'
        : `Scaling unsuccessful or insufficient (desired ${decision.desiredReplicas})`;

    const alertMessage: AlertMessage = {
      severity,
      title: `Virality surge alert`,
      details: {
        viralityScore: signal.viralityScore,
        projectedRPS: signal.projectedRPS,
        desiredReplicas: decision.desiredReplicas,
        rationale: decision.rationale,
        message,
      },
      sourceModule: 'module_22',
    };

    await notificationService.dispatch(alertMessage);
    logger.warn({ severity }, 'Alert dispatched via NotificationService.');
    return true; // always consider handled to prevent endless loop
  }
}

/**
 * Optional final link: Fallback logging (noop) – acts as a sink
 */
class NullRemediationHandler extends RemediationHandler {
  protected async process(): Promise<boolean> {
    logger.info('Reached end of remediation chain. No further action.');
    return true;
  }
}

/* -------------------------------------------------------------------------- */
/*                               Clients stubs                                */
/* -------------------------------------------------------------------------- */

/**
 *  In production these would be imported from shared infra packages.
 *  Types kept minimal for brevity.
 */

interface IKubeClient {
  getReplicaCount(deployment: string): Promise<number>;
  scaleDeployment(deployment: string, replicas: number): Promise<void>;
}

/* -------------------------------------------------------------------------- */
/*                         Virality correlation service                       */
/* -------------------------------------------------------------------------- */

class ViralityCorrelatorService {
  private consumer: Consumer;
  private readonly strategy: ScalingStrategy;
  private readonly remediationChain: RemediationHandler;

  constructor(
    kafka: Kafka,
    strategy: ScalingStrategy,
    remediationChain: RemediationHandler,
    private readonly topic = 'social_metrics',
  ) {
    this.strategy = strategy;
    this.remediationChain = remediationChain;
    this.consumer = kafka.consumer({ groupId: `virality-correlator-${strategy.name}` });
  }

  /**
   * Initialize Kafka consumer and internal listeners
   */
  async start(): Promise<void> {
    await this.consumer.connect();
    await this.consumer.subscribe({ topic: this.topic, fromBeginning: false });

    this.consumer.run({
      eachMessage: async (payload) => this.handleMessage(payload).catch(this.handleError),
    });

    bus.on(InternalBus.EVENTS.REMEDIATION_FAILED, (err) => {
      logger.error({ err }, 'Remediation failed – escalate if necessary');
    });

    logger.info('Virality correlator service started.');
  }

  async stop(): Promise<void> {
    await this.consumer.disconnect();
    logger.info('Virality correlator service stopped.');
  }

  /* ---------------------------- Private Helpers --------------------------- */

  /**
   * Parse and process each message coming from Kafka.
   */
  private async handleMessage({ message }: EachMessagePayload): Promise<void> {
    if (!message.value) return;
    const raw: SocialMetricEvent = JSON.parse(message.value.toString());

    const correlated = this.enrich(raw);
    if (correlated.viralityScore < 0.7) {
      // below threshold – ignore to reduce noise
      return;
    }

    bus.emit(InternalBus.EVENTS.VIRALITY_DETECTED, correlated);
    logger.debug({ correlated }, 'Virality detected');

    const decision = await this.strategy.assess(correlated);
    bus.emit(InternalBus.EVENTS.SCALE_DECISION, decision);
    logger.info({ decision }, 'Scaling decision generated');

    await this.remediationChain.handle(correlated, decision);
  }

  /**
   * Enrichment algorithm – a simplistic scoring heuristic
   */
  private enrich(event: SocialMetricEvent): CorrelatedSignal {
    const { likes, comments, shares, viewers } = event;

    // Weighted sum, tuned offline with historical data
    const viralityScore =
      0.4 * this.norm(likes) + 0.3 * this.norm(comments) + 0.2 * this.norm(shares) + 0.1 * this.norm(viewers);

    // Convert virality score to projected RPS using linear regression coefficients
    const projectedRPS = Math.round(viralityScore * 1500); // 1.0 ≈ 1500rps

    return { viralityScore, projectedRPS };
  }

  /**
   * Normalize raw counter via log scale to squish heavy tails
   */
  private norm(value: number): number {
    if (value <= 0) return 0;
    return Math.min(1, Math.log10(value + 1) / 4); // log10(10k) ~= 4
  }

  private handleError(err: unknown): void {
    logger.error(err, 'Error while processing Kafka message');
  }
}

