    cfg.kafkaBrokers   = (process.env.PS_KAFKA_BROKERS ?? 'localhost:9092').split(',');
    cfg.metricTopic    = process.env.PS_KAFKA_METRIC_TOPIC      ?? 'infra.metrics';
