     2→/**
     3→ * tests/test_utils.ts
     4→ *
     5→ * A shared test-helper library for the PulseSphere SocialOps code-base.
     6→ * -------------------------------------------------------------------
     7→ * All Jest/Vitest test-suites should import from this module instead of
     8→ * re-implementing ad-hoc mocks or helpers.  The utilities below are
     9→ * crafted to cover a wide range of common testing scenarios inside
    10→ * a large, event-driven, micro-service landscape:
    11→ *
    12→ *  1.  Synthetic telemetry & social-signal generators
    13→ *  2.  An in-memory event-bus that mimics Kafka / NATS semantics
    14→ *  3.  Async “eventually” expectations (handy for polling-based tests)
    15→ *  4.  Console spies & environment isolation helpers
    16→ *
    17→ * The goal is to keep individual test-files lean and focused on domain
    18→ * behaviour while centralising repetitive scaffolding concerns.
    19→ */
    20→
    21→import { EventEmitter } from 'events';
    22→import { randomUUID } from 'crypto';
    23→import { Mock, vi } from 'vitest'; // Works for Jest as well when using `jest` instead of `vi`
    24→import ms from 'ms';
    25→
    26→/* ------------------------------------------------------------------ */
    27→/*                         Domain-level fixtures                       */
    28→/* ------------------------------------------------------------------ */
    29→
    30→export type UserInteractionType =
    31→  | 'like'
    32→  | 'comment'
    33→  | 'share'
    34→  | 'view'
    35→  | 'reaction'
    36→  | 'follow';
    37→
    38→export interface TelemetryEvent {
    39→  id: string;                // UUID v4
    40→  timestamp: number;         // epoch ms
    41→  service: string;           // “feed-api”, “timeline-svc”, …
    42→  host: string;              // “ip-10-0-0-12”
    43→  metric: string;            // “cpu_usage”, “latency_p50”
    44→  value: number;             // numeric value
    45→  tags: Record<string, string>;
    46→  userInteraction?: {
    47→    type: UserInteractionType;
    48→    delta: number;           // how many interactions happened in this frame
    49→  };
    50→}
    51→
    52→/**
    53→ * Generate a realistic, deterministic (if seed passed) TelemetryEvent.
    54→ */
    55→export function createMockTelemetryEvent(
    56→  overrides: Partial<TelemetryEvent> = {},
    57→): TelemetryEvent {
    58→  const defaults: TelemetryEvent = {
    59→    id: randomUUID(),
    60→    timestamp: Date.now(),
    61→    service: `svc-${Math.floor(Math.random() * 10)}`,
    62→    host: `ip-10-0-0-${Math.floor(Math.random() * 255)}`,
    63→    metric: 'latency_p95',
    64→    value: Number((Math.random() * 800).toFixed(2)),
    65→    tags: {
    66→      env: 'test',
    67→      region: 'us-east-1',
    68→    },
    69→  };
    70→
    71→  // Randomly sprinkle a social interaction unless explicitly disabled
    72→  if (
    73→    overrides.userInteraction === undefined &&
    74→    Math.random() > 0.5
    75→  ) {
    76→    defaults.userInteraction = {
    77→      type: pickRandom<UserInteractionType>([
    78→        'like',
    79→        'comment',
    80→        'share',
    81→        'view',
    82→        'reaction',
    83→        'follow',
    84→      ]),
    85→      delta: Math.floor(Math.random() * 200),
    86→    };
    87→  }
    88→
    89→  return { ...defaults, ...overrides };
    90→}
    91→
    92→/* ------------------------------------------------------------------ */
    93→/*                         Event-Bus test-double                       */
    94→/* ------------------------------------------------------------------ */
    95→
    96→/**
    97→ * Lightweight in-memory pub/sub implementation that imitates the most
    98→ * essential semantics of Kafka/NATS used throughout PulseSphere.
    99→ *
   100→ *  - Topics are plain strings
   101→ *  - Messages are delivered in-order (sync inside the same tick)
   102→ *  - Back-pressure & re-delivery are *not* simulated
   103→ */
   104→export class InMemoryEventBus {
   105→  private emitter = new EventEmitter();
   106→
   107→  public publish<T>(topic: string, payload: T): void {
   108→    this.emitter.emit(topic, payload);
   109→  }
   110→
   111→  public subscribe<T>(
   112→    topic: string,
   113→    handler: (payload: T) => void | Promise<void>,
   114→  ): () => void {
   115→    this.emitter.on(topic, handler as any);
   116→
   117→    // Return unsubscribe fn
   118→    return () => this.emitter.off(topic, handler as any);
   119→  }
   120→
   121→  /**
   122→   * For tests that need to wait until *all* listeners processed the
   123→   * published message (when handlers are async).
   124→   */
   125→  public async publishAndDrain<T>(
   126→    topic: string,
   127→    payload: T,
   128→  ): Promise<void> {
   129→    const listeners = this.emitter.listeners(topic);
   130→
   131→    const results = listeners.map(async (listener) => listener(payload));
   132→    this.emitter.emit(topic, payload);
   133→    // Wait until every handler has been awaited
   134→    await Promise.allSettled(results);
   135→  }
   136→
   137→  public clearAll(): void {
   138→    this.emitter.removeAllListeners();
   139→  }
   140→}
   141→
   142→/* ------------------------------------------------------------------ */
   143→/*                       Asynchronous expect helper                   */
   144→/* ------------------------------------------------------------------ */
   145→
   146→/**
   147→ * Waits until the supplied expectation callback stops throwing or the
   148→ * timeout is reached. Helpful for eventual-consistency scenarios,
   149→ * especially with message queues or retry loops.
   150→ *
   151→ * Example:
   152→ *   await expectEventually(() => {
   153→ *     expect(storage.get('myKey')).toBeDefined();
   154→ *   });
   155→ */
   156→export async function expectEventually(
   157→  assertion: () => void | Promise<void>,
   158→  opts: {
   159→    timeout?: number | string;   // integer ms or “1s”, “500ms”
   160→    interval?: number | string;  // polling interval
   161→  } = {},
   162→): Promise<void> {
   163→  const timeout =
   164→    typeof opts.timeout === 'string'
   165→      ? ms(opts.timeout)
   166→      : opts.timeout ?? 2_000;
   167→  const interval =
   168→    typeof opts.interval === 'string'
   169→      ? ms(opts.interval)
   170→      : opts.interval ?? 50;
   171→
   172→  const startedAt = Date.now();
   173→  let lastErr: unknown;
   174→
   175→  // eslint-disable-next-line no-constant-condition
   176→  while (true) {
   177→    try {
   178→      await assertion();
   179→      return; // success 🎉
   180→    } catch (err) {
   181→      lastErr = err;
   182→      const elapsed = Date.now() - startedAt;
   183→      if (elapsed >= timeout) {
   184→        throw lastErr;
   185→      }
   186→      await wait(interval);
   187→    }
   188→  }
   189→}
   190→
   191→const wait = (t: number) => new Promise((res) => setTimeout(res, t));
   192→
   193→/* ------------------------------------------------------------------ */
   194→/*                     Console & env isolation helpers                */
   195→/* ------------------------------------------------------------------ */
   196→
   197→type ConsoleMethod = 'log' | 'info' | 'warn' | 'error' | 'debug';
   198→
   199→interface ConsoleSpies {
   200→  log: Mock;
   201→  info: Mock;
   202→  warn: Mock;
   203→  error: Mock;
   204→  debug: Mock;
   205→}
   206→
   207→/**
   208→ * Silence console output for noisy tests *and* give you access to the
   209→ * captured calls (returned mocks Reset via `restoreConsole`).
   210→ */
   211→export function mockConsole(): ConsoleSpies {
   212→  const original: Record<ConsoleMethod, (...args: any[]) => void> = {
   213→    log: console.log,
   214→    info: console.info,
   215→    warn: console.warn,
   216→    error: console.error,
   217→    debug: console.debug,
   218→  };
   219→
   220→  const spies = {} as ConsoleSpies;
   221→
   222→  (Object.keys(original) as ConsoleMethod[]).forEach((method) => {
   223→    // @ts-ignore – dynamic assignment is fine here
   224→    spies[method] = vi.fn();
   225→    console[method] = spies[method] as unknown as typeof console.log;
   226→  });
   227→
   228→  // Provide a restore hook on the spy object set
   229→  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
   230→  // @ts-ignore
   231→  spies.restore = () => {
   232→    (Object.keys(original) as ConsoleMethod[]).forEach((method) => {
   233→      console[method] = original[method];
   234→    });
   235→  };
   236→
   237→  return spies;
   238→}
   239→
   240→/**
   241→ * Temporarily override process.env keys for the duration of the test.
   242→ *
   243→ * Usage:
   244→ *   const restoreEnv = withEnv({ NODE_ENV: 'production' });
   245→ *   // ... run code
   246→ *   restoreEnv(); // resets previous values
   247→ */
   248→export function withEnv(
   249→  envOverrides: NodeJS.ProcessEnv,
   250→): () => void {
   251→  const previous = { ...process.env };
   252→
   253→  Object.entries(envOverrides).forEach(([key, val]) => {
   254→    process.env[key] = val;
   255→  });
   256→
   257→  return () => {
   258→    process.env = previous;
   259→  };
   260→}
   261→
   262→/* ------------------------------------------------------------------ */
   263→/*                             Test data pools                        */
   264→/* ------------------------------------------------------------------ */
   265→
   266→/** A curated list of real-world endpoints we can reuse in tests */
   267→export const SERVICE_NAMES = [
   268→  'user-svc',
   269→  'feed-api',
   270→  'search-edge',
   271→  'notification-worker',
   272→  'media-transcoder',
   273→  'analytics-ingestor',
   274→] as const;
   275→
   276→/** Some helper pick-random functions */
   277→export function pickRandom<T>(array: ReadonlyArray<T>): T {
   278→  return array[Math.floor(Math.random() * array.length)];
   279→}
   280→
   281→export function pickRandomService(): typeof SERVICE_NAMES[number] {
   282→  return pickRandom(SERVICE_NAMES);
   283→}
   284→
   285→/** Deep clone helper – useful when you want to ensure immutability */
   286→export function deepClone<T>(obj: T): T {
   287→  return JSON.parse(JSON.stringify(obj));
   288→}
   289→
   290→/* ------------------------------------------------------------------ */
   291→/* Default export – convenient aggregate                              */
   292→/* ------------------------------------------------------------------ */
   293→
   294→export default {
   295→  createMockTelemetryEvent,
   296→  InMemoryEventBus,
   297→  expectEventually,
   298→  mockConsole,
   299→  withEnv,
   300→  pickRandom,
   301→  pickRandomService,
   302→  deepClone,
   303→};
