   129→/* ─────────────────────────────── Strategy-Pattern Interfaces ──────────────────────────────── */
   130→interface AnomalyDetectionStrategy {
   131→  /** Return list of alerts generated for the given time-window */
   132→  detect(window: ReadonlyArray<CombinedEvent>): AnomalyAlert[];
   133→}
   134→
   135→/* ────────────────────────────── Concrete Strategy: Z-Score (generic) ────────────────────────── */
   136→class ZScoreStrategy implements AnomalyDetectionStrategy {
   137→  private readonly history: number[] = [];
   138→
   139→  constructor(
   140→    private readonly threshold: number, // e.g. 3 ⇒ ±3σ
   141→    private readonly windowSize: number,
   142→    private readonly logger: Logger,
   143→  ) {}
   144→
   145→  detect(window: ReadonlyArray<CombinedEvent>): AnomalyAlert[] {
   146→    const alerts: AnomalyAlert[] = [];
   147→
   148→    // Track only metric values; keep ring-buffer of last N
   149→    for (const ev of window) {
   150→      this.history.push(ev.value);
   151→      if (this.history.length > this.windowSize) this.history.shift();
   152→
   153→      if (this.history.length < this.windowSize) continue; // not enough data yet
   154→
   155→      const mean = this.history.reduce((a, b) => a + b, 0) / this.history.length;
   156→      const variance =
   157→        this.history.reduce((a, b) => a + (b - mean) ** 2, 0) / this.history.length;
   158→      const stdDev = Math.sqrt(variance);
   159→
   160→      // Avoid divide-by-0
   161→      if (stdDev === 0) continue;
   162→
   163→      const zScore = (ev.value - mean) / stdDev;
   164→      if (Math.abs(zScore) >= this.threshold) {
   165→        // escalate severity if social delta is simultaneously high
   166→        const severity: AnomalyAlert['severity'] =
   167→          ev.socialDelta > 50
   168→            ? 'HIGH'
   169→            : Math.abs(zScore) > this.threshold * 1.5
   170→            ? 'MEDIUM'
   171→            : 'LOW';
   172→
   173→        alerts.push({
   174→          timestamp: Date.now(),
   175→          severity,
   176→          reason: `Metric ${ev.metric} on ${ev.host} outlier – z=${zScore.toFixed(
   177→            2,
   178→          )}, socialDelta=${ev.socialDelta}`,
   179→          meta: { host: ev.host, metric: ev.metric, value: ev.value, zScore },
   180→        });
   181→      }
   182→    }
   183→
   184→    if (alerts.length) {
   185→      this.logger.info(`Z-Score detected ${alerts.length} alert(s)`);
   186→    }
   187→    return alerts;
   188→  }
   189→}
