   191→/* ─────────────── Concrete Strategy: Static Thresholds w/ Social Amplification ──────────────── */
   192→class ThresholdStrategy implements AnomalyDetectionStrategy {
   193→  constructor(
   194→    private readonly cpuThreshold: number,
   195→    private readonly memThreshold: number,
   196→    private readonly logger: Logger,
   197→  ) {}
   198→
   199→  detect(window: ReadonlyArray<CombinedEvent>): AnomalyAlert[] {
   200→    const alerts: AnomalyAlert[] = [];
   201→
   202→    for (const ev of window) {
   203→      if (
   204→        (ev.metric === 'cpu_load' && ev.value >= this.cpuThreshold) ||
   205→        (ev.metric === 'mem_util' && ev.value >= this.memThreshold)
   206→      ) {
   207→        const severity: AnomalyAlert['severity'] =
   208→          ev.socialDelta > 100 ? 'HIGH' : 'MEDIUM';
   209→
   210→        alerts.push({
   211→          timestamp: Date.now(),
   212→          severity,
   213→          reason: `Threshold exceeded: ${ev.metric}=${(ev.value * 100).toFixed(1)}%`,
   214→          meta: { host: ev.host, metric: ev.metric, value: ev.value, socialDelta: ev.socialDelta },
   215→        });
   216→      }
   217→    }
   218→
   219→    if (alerts.length) {
   220→      this.logger.info(`ThresholdStrategy detected ${alerts.length} alert(s)`);
   221→    }
   222→    return alerts;
   223→  }
   224→}
