   115→class HighCpuStrategy implements ScalingStrategy {
   116→  constructor(
   117→    private readonly meshClient: ServiceMeshClient,
   118→    private readonly highWaterMarkPct = 75,
   119→    private readonly lowWaterMarkPct  = 35,
   120→  ) {}
   121→
   122→  evaluate(metric: EnrichedMetric): ScalingCommand | undefined {
   123→    if (metric.cpuPct >= this.highWaterMarkPct) {
   124→      const factor = Math.max(1, Math.ceil(metric.cpuPct / 25));
   125→      return new ScaleUpCommand(this.meshClient, metric.appId, factor);
