     2→/******************************************************************************************
     3→ *  File:        src/module_33.ts
     4→ *  Project:     PulseSphere SocialOps (system_monitoring)
     5→ *
     6→ *  Description:
     7→ *  Social-Aware Auto-Scaler micro-service. Listens to infrastructure telemetry (CPU/memory)
     8→ *  from Apache Kafka, listens to near-real-time social-interaction signals from NATS,
     9→ *  merges the two streams and decides—via configurable Strategy pattern—whether capacity
    10→ *  should be scaled up/down. If a scaling decision is made it emits a Command event back
    11→ *  to the message bus. Additionally, it forwards critical alerts through a simple
    12→ *  Chain-of-Responsibility notifier pipeline (Slack → PagerDuty → Log).
    13→ *
    14→ *  NOTE: 3rd-party SDKs are thinly wrapped to allow mocking in unit tests; production
    15→ *  credentials and topics/subjects are injected via env-vars or Secret-Manager.
    16→ ******************************************************************************************/
    17→
    18→/* ================================== Imports ========================================= */
    19→
    20→import { Kafka, Producer, EachMessagePayload } from 'kafkajs';
    21→import { connect as natsConnect, NatsConnection, Subscription, JSONCodec } from 'nats';
    22→import pino, { Logger } from 'pino';
    23→import { v4 as uuid } from 'uuid';
    24→
    25→/* ============================== Domain & Contracts ================================== */
    26→
    27→/**
    28→ * Represents infrastructure telemetry pulled from Prometheus-push gateway (simplified).
    29→ */
    30→export interface SystemMetric {
    31→  timestamp: number;              // unix epoch ms
    32→  instanceId: string;             // k8s node or pod id
    33→  cpuLoadPct: number;             // e.g., 0.73 means 73%
    34→  memoryLoadPct: number;
    35→}
    36→
    37→/**
    38→ * Represents social-interaction spikes (likes, comments, shares, etc.)
    39→ */
    40→export interface SocialSignal {
    41→  timestamp: number;
    42→  campaignId?: string;
    43→  hashtag?: string;
    44→  deltaPerSecond: number;         // increase of interactions per sec
    45→}
    46→
    47→/**
    48→ * Consolidated view that Strategies will look at.
    49→ */
    50→export interface CombinedMetrics {
    51→  system: SystemMetric;
    52→  social?: SocialSignal;
    53→}
    54→
    55→/**
    56→ * Command event that goes onto Kafka for Orchestration service.
    57→ */
    58→export interface ScalingCommand {
    59→  commandId: string;
    60→  issuedAt: number;
    61→  targetGroup: string;            // e.g., "video-processor-pods"
    62→  action: 'SCALE_UP' | 'SCALE_DOWN';
    63→  desiredReplicas: number;
    64→  reason: string;
    65→}
    66→
    67→/* =========================== Strategy Pattern ======================================= */
    68→
    69→export interface ScalingStrategy {
    70→  readonly name: string;
    71→  evaluate(input: CombinedMetrics): ScalingCommand | null;
    72→}
    73→
    74→/**
    75→ * 1. Pure CPU strategy—scale if CPU surpasses threshold.
    76→ */
    77→export class CpuLoadStrategy implements ScalingStrategy {
    78→  readonly name = 'CpuLoadStrategy';
    79→
    80→  constructor(
    81→    private readonly cpuUpperThreshold = 0.8,
    82→    private readonly cpuLowerThreshold = 0.25,
    83→    private readonly maxReplicas = 16,
    84→    private readonly minReplicas = 2
    85→  ) {}
    86→
    87→  evaluate(input: CombinedMetrics): ScalingCommand | null {
    88→    const { cpuLoadPct, instanceId } = input.system;
    89→    let action: ScalingCommand['action'] | null = null;
    90→    let desired: number | null = null;
    91→
    92→    if (cpuLoadPct >= this.cpuUpperThreshold) {
    93→      action = 'SCALE_UP';
    94→      desired = Math.min(this.maxReplicas, Math.ceil(cpuLoadPct * 10));
    95→    } else if (cpuLoadPct <= this.cpuLowerThreshold) {
    96→      action = 'SCALE_DOWN';
    97→      desired = Math.max(this.minReplicas, Math.floor(cpuLoadPct * 10));
    98→    }
    99→
   100→    if (action && desired !== null) {
   101→      return {
   102→        commandId: uuid(),
   103→        issuedAt: Date.now(),
   104→        targetGroup: instanceId,
   105→        action,
   106→        desiredReplicas: desired,
   107→        reason: `CPU load ${cpuLoadPct * 100}% triggered ${action}`
   108→      };
   109→    }
   110→    return null;
   111→  }
   112→}
   113→
   114→/**
   115→ * 2. Social trend strategy—scale on viral spikes regardless of current CPU.
   116→ */
   117→export class SocialTrendingStrategy implements ScalingStrategy {
   118→  readonly name = 'SocialTrendingStrategy';
   119→
   120→  constructor(
   121→    private readonly spikeThreshold = 5000,        // interactions/sec
   122→    private readonly surgeReplicas = 8
   123→  ) {}
   124→
   125→  evaluate(input: CombinedMetrics): ScalingCommand | null {
   126→    if (!input.social) return null;
   127→    const { deltaPerSecond, hashtag } = input.social;
   128→    if (deltaPerSecond >= this.spikeThreshold) {
   129→      return {
   130→        commandId: uuid(),
   131→        issuedAt: Date.now(),
   132→        targetGroup: hashtag ?? 'global',
   133→        action: 'SCALE_UP',
   134→        desiredReplicas: this.surgeReplicas,
   135→        reason: `Social spike (${deltaPerSecond}/s) for #${hashtag}`
   136→      };
   137→    }
   138→    return null;
   139→  }
   140→}
   141→
   142→/**
   143→ * 3. Hybrid strategy—showcases Strategy composition.
   144→ */
   145→export class HybridStrategy implements ScalingStrategy {
   146→  readonly name = 'HybridStrategy';
   147→  private readonly innerStrategies: ScalingStrategy[];
   148→
   149→  constructor(...strategies: ScalingStrategy[]) {
   150→    this.innerStrategies = strategies;
   151→  }
   152→
   153→  evaluate(input: CombinedMetrics): ScalingCommand | null {
   154→    for (const strat of this.innerStrategies) {
   155→      const cmd = strat.evaluate(input);
   156→      if (cmd) return cmd;
   157→    }
   158→    return null;
   159→  }
   160→}
