   148→export class SpikeDetectionStrategy implements CorrelationStrategy {
   149→  readonly name = 'SpikeDetection';
   150→  private readonly windowMs: number;
   151→  private readonly history: Map<string, InfrastructureMetric[]> = new Map();
   152→
   153→  constructor(windowMs = 5 * 60_000 /* 5 min */) {
   154→    this.windowMs = windowMs;
   155→  }
   156→
   157→  compute(
   158→    signal: SocialSignal,
   159→    metric: InfrastructureMetric,
   160→  ): CorrelationResult {
   161→    const list = this.history.get(metric.cluster) ?? [];
   162→    // prune old samples
   163→    const freshSamples = list.filter(
   164→      (m) => metric.timestamp - m.timestamp <= this.windowMs,
   165→    );
   166→    freshSamples.push(metric);
   167→    this.history.set(metric.cluster, freshSamples);
   168→
   169→    const avgCpu =
   170→      freshSamples.reduce((acc, m) => acc + m.cpuUtil, 0) /
   171→      Math.max(freshSamples.length, 1);
   172→    const cpuSpike = metric.cpuUtil > avgCpu * 1.5 && metric.cpuUtil > 80;
