   270→/**
   271→ * Subscribes to two EventEmitters (social + infra) and attempts to correlate
   272→ * events sharing the nearest timestamp within `orphanWindowMs`.
   273→ */
   274→export class SocialCorrelationEngine extends EventEmitter {
   275→  private readonly socialStream = new EventEmitter();
   276→  private readonly infraStream = new EventEmitter();
   277→  private readonly strategies: CorrelationStrategy[];
   278→  private readonly orphanWindowMs: number;
   279→  private readonly orphanSocial: SocialSignal[] = [];
   280→  private readonly orphanInfra: InfrastructureMetric[] = [];
   281→  private readonly remediationChain: RemediationHandler;
   282→
   283→  constructor({
   284→    strategies = [
   285→      new PearsonLikesToRequestStrategy(),
   286→      new SpikeDetectionStrategy(),
   287→    ],
   288→    remediationChain,
   289→    orphanWindowMs = 15_000,
   290→  }: CorrelationEngineOptions = {}) {
   291→    super();
   292→    this.strategies = strategies;
   293→    this.orphanWindowMs = orphanWindowMs;
   294→    this.remediationChain =
   295→      remediationChain ??
   296→      new ScaleUpHandler()
   297→        .setNext(new CacheWarmUpHandler())
   298→        .setNext(new NotifySREHandler());
   299→
   300→    this.socialStream.on('social', (sig: SocialSignal) =>
   301→      this.handleSocial(sig),
   302→    );
   303→    this.infraStream.on('infra', (met: InfrastructureMetric) =>
   304→      this.handleInfra(met),
   305→    );
   306→  }
