   309→
   310→  publishSocial(signal: SocialSignal): void {
   311→    this.socialStream.emit('social', signal);
   312→  }
   313→
   314→  publishInfra(metric: InfrastructureMetric): void {
   315→    this.infraStream.emit('infra', metric);
   316→  }
   317→
   318→  /* --------------------------- private logic ---------------------------- */
   319→
   320→  private handleSocial(signal: SocialSignal): void {
   321→    try {
   322→      const match = this.findClosestInfra(signal.timestamp);
   323→      if (match) {
   324→        this.correlate(signal, match);
   325→      } else {
   326→        this.orphanSocial.push(signal);
   327→        this.cleanupOrphans();
   328→      }
   329→    } catch (err) {
   330→      log.error('Failed to handle social signal', err);
   331→    }
   332→  }
   333→
   334→  private handleInfra(metric: InfrastructureMetric): void {
   335→    try {
   336→      const match = this.findClosestSocial(metric.timestamp);
   337→      if (match) {
   338→        this.correlate(match, metric);
   339→      } else {
   340→        this.orphanInfra.push(metric);
   341→        this.cleanupOrphans();
   342→      }
   343→    } catch (err) {
   344→      log.error('Failed to handle infra metric', err);
   345→    }
   346→  }
   347→
   348→  private findClosestInfra(ts: number): InfrastructureMetric | undefined {
   349→    let closestIdx = -1;
   350→    let minDelta = Infinity;
   351→    for (let i = 0; i < this.orphanInfra.length; i++) {
   352→      const delta = Math.abs(this.orphanInfra[i].timestamp - ts);
   353→      if (delta < minDelta && delta <= this.orphanWindowMs) {
   354→        minDelta = delta;
   355→        closestIdx = i;
   356→      }
   357→    }
   358→    if (closestIdx > -1) {
   359→      return this.orphanInfra.splice(closestIdx, 1)[0];
   360→    }
   361→    return undefined;
   362→  }
   363→
   364→  private findClosestSocial(ts: number): SocialSignal | undefined {
   365→    let closestIdx = -1;
   366→    let minDelta = Infinity;
   367→    for (let i = 0; i < this.orphanSocial.length; i++) {
   368→      const delta = Math.abs(this.orphanSocial[i].timestamp - ts);
   369→      if (delta < minDelta && delta <= this.orphanWindowMs) {
   370→        minDelta = delta;
   371→        closestIdx = i;
   372→      }
   373→    }
   374→    if (closestIdx > -1) {
   375→      return this.orphanSocial.splice(closestIdx, 1)[0];
   376→    }
   377→    return undefined;
   378→  }
   379→
   380→  private async correlate(
   381→    signal: SocialSignal,
   382→    metric: InfrastructureMetric,
   383→  ): Promise<void> {
   384→    for (const strategy of this.strategies) {
   385→      const result = strategy.compute(signal, metric);
   386→      this.emit('correlation', result);
   387→      log.info(
   388→        `Strategy ${strategy.name} produced corrId ${result.correlationId} (significant=${result.significant})`,
   389→      );
   390→      // Fire remediation asynchronously; do not block stream
   391→      /* eslint-disable-next-line @typescript-eslint/no-floating-promises */
   392→      this.remediationChain.handle({ correlation: result });
   393→    }
   394→  }
   395→
   396→  private cleanupOrphans(): void {
   397→    const threshold = now() - this.orphanWindowMs;
   398→    this.orphanSocial.splice(
   399→      0,
   400→      this.orphanSocial.findIndex((s) => s.timestamp >= threshold),
   401→    );
   402→    this.orphanInfra.splice(
   403→      0,
   404→      this.orphanInfra.findIndex((m) => m.timestamp >= threshold),
   405→    );
   406→  }
   407→}
