   161→function deepMerge<T extends Record<string, unknown>, U extends Record<string, unknown>>(lhs: T, rhs: U): T & U {
   162→  const result = { ...lhs } as T & U;
   163→
   164→  Object.entries(rhs).forEach(([key, value]) => {
