      const payload = {
        to: this.recipients,
        subject: `[PulseSphere] ${message.severity.toUpperCase()} – ${message.title}`,
        body: JSON.stringify(
          {
            severity: message.severity,
            title: message.title,
            details: message.details,
            sourceModule: message.sourceModule,
            timestamp: new Date().toISOString(),
          },
          null,
          2,
        ),
      };

      logger.info(
        { channel: this.name, recipients: this.recipients, title: message.title },
        'Email notification sent',
      );

      // Placeholder for actual HTTP call:
      // await axios.post(`${this.smtpEndpoint}/send`, payload);
    } catch (err) {
      logger.error({ err, channel: this.name }, 'Failed to send email notification');
      throw err;
    }
  }
}

/**
 * Webhook notification channel.
 * Posts alerts to external services like Slack, Teams, PagerDuty, etc.
 */
export class WebhookChannel implements NotificationChannel {
  readonly name: string;

  constructor(
    private readonly webhookUrl: string,
    private readonly channelName: string = 'webhook',
  ) {
    this.name = channelName;
  }

  async send(message: AlertMessage): Promise<void> {
    try {
      const payload = this.formatPayload(message);

      logger.info(
        { channel: this.name, title: message.title, severity: message.severity },
        'Webhook notification sent',
      );

      // Placeholder for actual HTTP call:
      // await axios.post(this.webhookUrl, payload);
    } catch (err) {
      logger.error({ err, channel: this.name }, 'Failed to send webhook notification');
      throw err;
    }
  }

  private formatPayload(message: AlertMessage): Record<string, unknown> {
    // Format for Slack-style webhooks
    if (this.webhookUrl.includes('hooks.slack.com')) {
      return {
        text: `*${message.severity.toUpperCase()}* alert from *${message.sourceModule}*`,
        attachments: [
          {
            color: this.getSeverityColor(message.severity),
            title: message.title,
            fields: Object.entries(message.details).map(([key, value]) => ({
              title: key,
              value: String(value),
              short: true,
            })),
          },
        ],
      };
    }

    // Format for Microsoft Teams
    if (this.webhookUrl.includes('teams.microsoft.com')) {
      return {
        '@type': 'MessageCard',
        themeColor: this.getSeverityColor(message.severity),
        title: `${message.severity.toUpperCase()}: ${message.title}`,
        text: `Alert from ${message.sourceModule}`,
        sections: [
          {
            facts: Object.entries(message.details).map(([key, value]) => ({
              name: key,
              value: String(value),
            })),
          },
        ],
      };
    }

    // Format for PagerDuty
    if (this.webhookUrl.includes('pagerduty.com')) {
      return {
        routing_key: notificationConfig.pagerDutyKey,
        event_action: 'trigger',
        payload: {
          summary: `${message.title} [${message.sourceModule}]`,
          severity: message.severity === 'critical' ? 'critical' : message.severity === 'warning' ? 'warning' : 'info',
          source: `PulseSphere/${message.sourceModule}`,
          custom_details: message.details,
        },
      };
    }

    // Generic format
    return {
      severity: message.severity,
      title: message.title,
      details: message.details,
      sourceModule: message.sourceModule,
      timestamp: new Date().toISOString(),
    };
  }

  private getSeverityColor(severity: AlertSeverity): string {
    switch (severity) {
      case 'critical':
        return '#dc3545'; // red
      case 'warning':
        return '#ffc107'; // yellow
      case 'info':
        return '#17a2b8'; // blue
      default:
        return '#6c757d'; // gray
    }
  }
}

/**
 * Log notification channel.
 * Writes alerts to the application log with appropriate severity level.
 */
export class LogChannel implements NotificationChannel {
  readonly name = 'log';

  private readonly channelLogger: pino.Logger;

  constructor() {
    this.channelLogger = pino({
      name: 'alert-log-channel',
      level: 'trace',
    });
  }

  async send(message: AlertMessage): Promise<void> {
    const logPayload = {
      alertTitle: message.title,
      alertSeverity: message.severity,
      sourceModule: message.sourceModule,
      details: message.details,
      timestamp: new Date().toISOString(),
    };

    switch (message.severity) {
      case 'critical':
        this.channelLogger.fatal(logPayload, `CRITICAL ALERT: ${message.title}`);
        break;
      case 'warning':
        this.channelLogger.warn(logPayload, `WARNING ALERT: ${message.title}`);
        break;
      case 'info':
      default:
        this.channelLogger.info(logPayload, `INFO ALERT: ${message.title}`);
        break;
    }
  }
}

/* -------------------------------------------------------------------------- */
/*                           NotificationService                               */
/* -------------------------------------------------------------------------- */

/**
 * Central notification service that dispatches alerts to configured channels.
 */
export class NotificationService {
  private readonly channels: NotificationChannel[];
  private readonly serviceLogger: pino.Logger;

  constructor(channels: NotificationChannel[]) {
    this.channels = channels;
    this.serviceLogger = pino({
      name: 'notification-service',
      level: process.env.LOG_LEVEL ?? 'info',
    });
  }

  /**
   * Dispatch an alert message to all configured notification channels.
   * Errors from individual channels are logged but do not stop other channels.
   *
   * @param alert The alert message to dispatch
   */
  async dispatch(alert: AlertMessage): Promise<void> {
    this.serviceLogger.debug(
      { alert, channelCount: this.channels.length },
      'Dispatching alert to notification channels',
    );

    const results = await Promise.allSettled(
      this.channels.map(async (channel) => {
        try {
          await channel.send(alert);
          return { channel: channel.name, success: true };
        } catch (err) {
          this.serviceLogger.error(
            { err, channel: channel.name, alertTitle: alert.title },
            'Channel failed to send notification',
          );
          return { channel: channel.name, success: false, error: err };
        }
      }),
    );

    const failedChannels = results.filter(
      (r) => r.status === 'rejected' || (r.status === 'fulfilled' && !r.value.success),
    );

    if (failedChannels.length > 0) {
      this.serviceLogger.warn(
        { failedCount: failedChannels.length, totalChannels: this.channels.length },
        'Some notification channels failed',
      );
    }
  }

  /**
   * Get the list of configured channel names.
   */
  getChannelNames(): string[] {
    return this.channels.map((c) => c.name);
  }
}

/* -------------------------------------------------------------------------- */
/*                         Singleton Instance Factory                          */
/* -------------------------------------------------------------------------- */

/**
 * Create the default NotificationService instance with channels
 * configured from the notification config.
 */
function createNotificationService(): NotificationService {
  const channels: NotificationChannel[] = [];

  // Always add the log channel as a fallback
  channels.push(new LogChannel());

  // Add email channel if configured
  if (notificationConfig.smtpEndpoint && notificationConfig.emailRecipients.length > 0) {
    channels.push(
      new EmailChannel(notificationConfig.smtpEndpoint, notificationConfig.emailRecipients),
    );
  }

  // Add Slack webhook channel if configured
  if (notificationConfig.slackWebhookUrl) {
    channels.push(new WebhookChannel(notificationConfig.slackWebhookUrl, 'slack'));
  }

  // Add PagerDuty channel if configured
  if (notificationConfig.pagerDutyEndpoint && notificationConfig.pagerDutyKey) {
    channels.push(new WebhookChannel(notificationConfig.pagerDutyEndpoint, 'pagerduty'));
  }

  // Add Teams webhook channel if configured
  if (notificationConfig.teamsWebhookUrl) {
    channels.push(new WebhookChannel(notificationConfig.teamsWebhookUrl, 'teams'));
  }

  logger.info(
    { channels: channels.map((c) => c.name) },
    'NotificationService initialized with channels',
  );

  return new NotificationService(channels);
}

/**
 * Singleton instance of the NotificationService.
 * Import this to send alerts from anywhere in the application.
 */
export const notificationService = createNotificationService();

/* -------------------------------------------------------------------------- */
/*                              Convenience Exports                            */
/* -------------------------------------------------------------------------- */

export { notificationConfig };

