/**
 * PulseSphere SocialOps – Notification Configuration
 * ====================================================
 * src/config/notifications.ts
 *
 * Centralized configuration for the notification service.
 * All hardcoded alerting configuration (email addresses, webhook URLs, API keys)
 * is consolidated here for easy management and environment-specific overrides.
 *
 * Configuration is loaded from environment variables with sensible defaults.
 */

/* -------------------------------------------------------------------------- */
/*                         Configuration Interface                             */
/* -------------------------------------------------------------------------- */

/**
 * Configuration structure for the notification service.
 */
export interface NotificationConfig {
  /** SMTP endpoint for sending email alerts */
  smtpEndpoint: string;
  /** List of email recipients for alert notifications */
  emailRecipients: string[];
  /** Slack webhook URL for posting alerts */
  slackWebhookUrl: string | undefined;
  /** Microsoft Teams webhook URL for posting alerts */
  teamsWebhookUrl: string | undefined;
  /** PagerDuty events API endpoint */
  pagerDutyEndpoint: string;
  /** PagerDuty routing/integration key */
  pagerDutyKey: string | undefined;
  /** OpsGenie API endpoint */
  opsGenieEndpoint: string | undefined;
  /** OpsGenie API key */
  opsGenieKey: string | undefined;
  /** Whether alerting is globally enabled */
  alertingEnabled: boolean;
  /** Minimum severity level to trigger alerts: 'info', 'warning', 'critical' */
  minAlertSeverity: 'info' | 'warning' | 'critical';
}

/* -------------------------------------------------------------------------- */
/*                         Environment Configuration                           */
/* -------------------------------------------------------------------------- */

/**
 * Parse a comma-separated environment variable into an array.
 */
function parseArrayEnv(value: string | undefined, defaultValue: string[] = []): string[] {
  if (!value) return defaultValue;
  return value
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean);
}

/**
 * Parse a boolean environment variable.
 */
function parseBoolEnv(value: string | undefined, defaultValue: boolean): boolean {
  if (!value) return defaultValue;
  return /^(true|1|yes)$/i.test(value);
}

/**
 * The centralized notification configuration.
 *
 * Values are loaded from environment variables with the following mapping:
 *
 * | Config Property      | Environment Variable           | Default Value                              |
 * |---------------------|--------------------------------|-------------------------------------------|
 * | smtpEndpoint        | SMTP_ENDPOINT                  | https://smtp.internal                     |
 * | emailRecipients     | ALERT_EMAIL_RECIPIENTS         | ['ops@pulsesphere.io']                    |
 * | slackWebhookUrl     | SLACK_WEBHOOK                  | https://hooks.slack.com/services/dummy    |
 * | teamsWebhookUrl     | TEAMS_WEBHOOK                  | undefined                                 |
 * | pagerDutyEndpoint   | PAGERDUTY_ENDPOINT             | https://events.pagerduty.com/v2/enqueue   |
 * | pagerDutyKey        | PAGERDUTY_KEY                  | undefined                                 |
 * | opsGenieEndpoint    | OPSGENIE_ENDPOINT              | undefined                                 |
 * | opsGenieKey         | OPSGENIE_KEY                   | undefined                                 |
 * | alertingEnabled     | ALERTING_ENABLED               | true                                      |
 * | minAlertSeverity    | MIN_ALERT_SEVERITY             | 'warning'                                 |
 */
export const notificationConfig: NotificationConfig = {
  // Email configuration
  smtpEndpoint: process.env.SMTP_ENDPOINT ?? 'https://smtp.internal',
  emailRecipients: parseArrayEnv(process.env.ALERT_EMAIL_RECIPIENTS, ['ops@pulsesphere.io']),

  // Slack configuration
  slackWebhookUrl:
    process.env.SLACK_WEBHOOK ??
    process.env.PS_ALERT_SLACK_WEBHOOK ??
    'https://hooks.slack.com/services/dummy',

  // Microsoft Teams configuration
  teamsWebhookUrl: process.env.TEAMS_WEBHOOK ?? process.env.TEAMS_WEBHOOK_URL,

  // PagerDuty configuration
  pagerDutyEndpoint:
    process.env.PAGERDUTY_ENDPOINT ?? 'https://events.pagerduty.com/v2/enqueue',
  pagerDutyKey: process.env.PAGERDUTY_KEY ?? process.env.PS_ALERT_PD_KEY,

  // OpsGenie configuration
  opsGenieEndpoint: process.env.OPSGENIE_ENDPOINT,
  opsGenieKey: process.env.OPSGENIE_KEY,

  // Global alerting settings
  alertingEnabled: parseBoolEnv(process.env.ALERTING_ENABLED, true),
  minAlertSeverity: (process.env.MIN_ALERT_SEVERITY as NotificationConfig['minAlertSeverity']) ?? 'warning',
};

/* -------------------------------------------------------------------------- */
/*                              Validation                                     */
/* -------------------------------------------------------------------------- */

/**
 * Validate the notification configuration at startup.
 * Logs warnings for missing optional configuration.
 */
export function validateNotificationConfig(): void {
  const warnings: string[] = [];

  if (!notificationConfig.pagerDutyKey) {
    warnings.push('PAGERDUTY_KEY not set – PagerDuty alerts will be disabled');
  }

  if (notificationConfig.slackWebhookUrl?.includes('dummy')) {
    warnings.push('SLACK_WEBHOOK appears to be a placeholder – Slack alerts may not work');
  }

  if (warnings.length > 0) {
    // eslint-disable-next-line no-console
    console.warn('[NotificationConfig] Configuration warnings:');
    warnings.forEach((w) => console.warn(`  - ${w}`));
  }
}

// Run validation on module load in non-test environments
if (process.env.NODE_ENV !== 'test') {
  validateNotificationConfig();
}

