ld * 1.2 ? 'CRIT' : 'WARN';\n\n      const alert: Alert = {\n        tenantId: event.tenantId,\n        severity,\n        metricName: 'cpu_usage',\n        observedValue: cpuUsage,\n        threshold,\n        context: { socialMetric: event },\n      };\n\n      this.alertCounter.inc({ ...tenantLabel, severity });\n      logger.warn(\n        `Alert triggered tenant=${event.tenantId} cpu=${cpuUsage.toFixed(2)} ` +\n        `threshold=${threshold.toFixed(2)} severity=${severity}`,\n      );\n\n      await dispatchAlert(alert);\n    } else {\n      logger.debug(\n        `CPU within threshold tenant=${event.tenantId} cpu=${cpuUsage.toFixed(2)} ` +\n        `threshold=${threshold.toFixed(2)}`,\n      );\n    }\n  }\n}\n\n/* -------------------------------------------------------------------------------------------------\n * Bootstrap – wire everything together if executed directly\n * -------------------------------------------------------------------------------------------------*/\n\nif (require.main === module) {\n  (async () => {\n    try {\n      // Instantiate manager with strategies (no longer needs escalation chain)\n      const manager = new AdaptiveThresholdManager(75 /* default CPU threshold */)\n        .addStrategy(new TrendingBoostStrategy())\n        .addStrategy(new NightTimeRelaxStrategy());\n\n      // Observer listens to Kafka topic\n      const observer = new KafkaSocialMetricObserver(\n        (process.env.KAFKA_BROKERS ?? 'localhost:9092').split(','),\n        'adaptive-threshold-group',\n      );\n\n      await observer.onEvent('social-metrics', (evt) => manager.handleSocialEvent(evt));\n\n      // Expose Prometheus endpoint\n      const port = Number(process.env.METRICS_PORT ?? 9100);\n      /* eslint-disable @typescript-eslint/no-var-requires */\n      const http = require('http');\n      http.createServer((_, res) => {\n        res.writeHead(200, { 'Content-Type': register.contentType });\n        register.metrics().then((m: string) => res.end(m));\n      }).listen(port, () => logger.info(`Metrics exposed on :${port}/`));\n    } catch (err) {\n      logger.error('Failed to bootstrap AdaptiveThresholdManager', err as Error);\n      process.exit(1);\n    }\n  })();\n}\n", "structuredPatch": [{"oldStart": 1, "oldLines": 4, "newStart": 1, "newLines": 3, "lines": ["-```typescript", " /**************************************************************************************************", "  * PulseSphere SocialOps – Adaptive Threshold Manager                                             *", "  * ------------------------------------------------------------------------------------------------"]}, {"oldStart": 7, "oldLines": 16, "newStart": 6, "newLines": 16, "lines": ["  *              real-time social signals (likes, comments, shares, hashtag bursts) into           *", "  *              the decision model. Combines Strategy, Observer and Chain-of-Responsibility       *", "  *              patterns to (1) calculate adaptive thresholds, (2) observe social-metric events   *", "- *              over Kafka, and (3) escalate incidents through multiple notifiers.                *", "- *                                                                                                ", "+ *              over Kafka, and (3) escalate incidents through the centralized NotificationService*", "+ *", "  * Author:      PulseSphere Engineering Team                                                      *", "  **************************************************************************************************/", " ", " /* eslint-disable import/order */", " import { Kafka, EachMessagePayload } from 'kafkajs';", " import { Counter, Gauge, register } from 'prom-client';", "-import axios from 'axios';", " import winston from 'winston';", "+import { notificationService, AlertMessage } from './services/notificationService';", " ", " /* -------------------------------------------------------------------------------------------------", "  * Dom