     7→ *  Social-Aware Auto-Scaler micro-service. Listens to infrastructure telemetry (CPU/memory)
     8→ *  from Apache Kafka, listens to near-real-time social-interaction signals from NATS,
     9→ *  merges the two streams and decides—via configurable Strategy pattern—whether capacity
    10→ *  should be scaled up/down. If a scaling decision is made it emits a Command event back
    11→ *  to the message bus. Additionally, it forwards critical alerts through a simple
    12→ *  Chain-of-Responsibility notifier pipeline (Slack → PagerDuty → Log).
    13→ *
    14→ *  NOTE: 3rd-party SDKs are thinly wrapped to allow mocking in unit tests; production
    15→ *  credentials and topics/subjects are injected via env-vars or Secret-Manager.
    16→ ******************************************************************************************/
    17→
    18→/* ================================== Imports ========================================= */
    19→
    20→import { Kafka, Producer, EachMessagePayload } from 'kafkajs';
    21→import { connect as natsConnect, NatsConnection, Subscription, JSONCodec } from 'nats';
    22→import pino, { Logger } from 'pino';
    23→import { v4 as uuid } from 'uuid';
    24→
    25→/* ============================== Domain & Contracts ================================== */
    26→
    27→/**
    28→ * Represents infrastructure telemetry pulled from Prometheus-push gateway (simplified).
    29→ */
    30→export interface SystemMetric {
    31→  timestamp: number;              // unix epoch ms
    32→  instanceId: string;             // k8s node or pod id
    33→  cpuLoadPct: number;             // e.g., 0.73 means 73%
    34→  memoryLoadPct: number;
    35→}
    36→
    37→/**
    38→ * Represents social-interaction spikes (likes, comments, shares, etc.)
    39→ */
    40→export interface SocialSignal {
    41→  timestamp: number;
    42→  campaignId?: string;
    43→  hashtag?: string;
    44→  deltaPerSecond: number;         // increase of interactions per sec
    45→}
    46→
    47→/**
    48→ * Consolidated view that Strategies will look at.
    49→ */
    50→export interface CombinedMetrics {
    51→  system: SystemMetric;
    52→  social?: SocialSignal;
    53→}
    54→
    55→/**
    56→ * Command event that goes onto Kafka for Orchestration service.
    57→ */
    58→export interface ScalingCommand {
    59→  commandId: string;
    60→  issuedAt: number;
    61→  targetGroup: string;            // e.g., "video-processor-pods"
    62→  action: 'SCALE_UP' | 'SCALE_DOWN';
    63→  desiredReplicas: number;
    64→  reason: string;
    65→}
    66→
    67→/* =========================== Strategy Pattern ======================================= */
    68→
    69→export interface ScalingStrategy {
    70→  readonly name: string;
    71→  evaluate(input: CombinedMetrics): ScalingCommand | null;
    72→}
    73→
    74→/**
    75→ * 1. Pure CPU strategy—scale if CPU surpasses threshold.
    76→ */
    77→export class CpuLoadStrategy implements ScalingStrategy {
    78→  readonly name = 'CpuLoadStrategy';
    79→
    80→  constructor(
    81→    private readonly cpuUpperThreshold = 0.8,
    82→    private readonly cpuLowerThreshold = 0.25,
    83→    private readonly maxReplicas = 16,
    84→    private readonly minReplicas = 2
    85→  ) {}
    86→
    87→  evaluate(input: CombinedMetrics): ScalingCommand | null {
    88→    const { cpuLoadPct, instanceId } = input.system;
    89→    let action: ScalingCommand['action'] | null = null;
    90→    let desired: number | null = null;
    91→
    92→    if (cpuLoadPct >= this.cpuUpperThreshold) {
    93→      action = 'SCALE_UP';
    94→      desired = Math.min(this.maxReplicas, Math.ceil(cpuLoadPct * 10));
    95→    } else if (cpuLoadPct <= this.cpuLowerThreshold) {
    96→      action = 'SCALE_DOWN';
    97→      desired = Math.max(this.minReplicas, Math.floor(cpuLoadPct * 10));
    98→    }
    99→
   100→    if (action && desired !== null) {
   101→      return {
   102→        commandId: uuid(),
   103→        issuedAt: Date.now(),
   104→        targetGroup: instanceId,
   105→        action,
   106→        desiredReplicas: desired,
   107→        reason: `CPU load ${cpuLoadPct * 100}% triggered ${action}`
   108→      };
   109→    }
   110→    return null;
   111→  }
   112→}
   113→
   114→/**
   115→ * 2. Social trend strategy—scale on viral spikes regardless of current CPU.
   116→ */
   117→export class SocialTrendingStrategy implements ScalingStrategy {
   118→  readonly name = 'SocialTrendingStrategy';
   119→
   120→  constructor(
   121→    private readonly spikeThreshold = 5000,        // interactions/sec
   122→    private readonly surgeReplicas = 8
   123→  ) {}
   124→
   125→  evaluate(input: CombinedMetrics): ScalingCommand | null {
   126→    if (!input.social) return null;
   127→    const { deltaPerSecond, hashtag } = input.social;
   128→    if (deltaPerSecond >= this.spikeThreshold) {
   129→      return {
   130→        commandId: uuid(),
   131→        issuedAt: Date.now(),
   132→        targetGroup: hashtag ?? 'global',
   133→        action: 'SCALE_UP',
   134→        desiredReplicas: this.surgeReplicas,
   135→        reason: `Social spike (${deltaPerSecond}/s) for #${hashtag}`
   136→      };
   137→    }
   138→    return null;
   139→  }
   140→}
   141→
   142→/**
   143→ * 3. Hybrid strategy—showcases Strategy composition.
   144→ */
   145→export class HybridStrategy implements ScalingStrategy {
   146→  readonly name = 'HybridStrategy';
   147→  private readonly innerStrategies: ScalingStrategy[];
   148→
   149→  constructor(...strategies: ScalingStrategy[]) {
   150→    this.innerStrategies = strategies;
   151→  }
   152→
   153→  evaluate(input: CombinedMetrics): ScalingCommand | null {
   154→    for (const strat of this.innerStrategies) {
   155→      const cmd = strat.evaluate(input);
   156→      if (cmd) return cmd;
   157→    }
   158→    return null;
   159→  }
   160→}
   161→
   162→/* =================== Chain-of-Responsibility for Alerting =========================== */
   163→
   164→interface AlertHandler {
   165→  setNext(handler: AlertHandler): AlertHandler;
   166→  handle(message: string): Promise<void>;
   167→}
   168→
   169→abstract class AbstractHandler implements AlertHandler {
   170→  protected nextHandler?: AlertHandler;
   171→  setNext(handler: AlertHandler): AlertHandler {
   172→    this.nextHandler = handler;
   173→    return handler;
   174→  }
   175→  async handle(message: string): Promise<void> {
   176→    if (this.nextHandler) {
   177→      await this.nextHandler.handle(message);
   178→    }
   179→  }
   180→}
   181→
   182→class SlackNotifierHandler extends AbstractHandler {
   183→  constructor(private readonly logger: Logger) { super(); }
   184→  async handle(message: string): Promise<void> {
   185→    try {
   186→      // Placeholder for Slack webhook call
   187→      this.logger.info({ msg: 'SlackNotifier', message });
   188→      // Success, stop chain.
   189→    } catch (err) {
   190→      this.logger.error({ err, msg: 'SlackNotifierFailed' });
   191→      await super.handle(message);
   192→    }
   193→  }
   194→}
   195→
   196→class PagerDutyHandler extends AbstractHandler {
   197→  constructor(private readonly logger: Logger) { super(); }
   198→  async handle(message: string): Promise<void> {
   199→    try {
   200→      // Placeholder for PagerDuty event trigger
   201→      this.logger.info({ msg: 'PagerDutyNotifier', message });
   202→    } catch (err) {
   203→      this.logger.error({ err, msg: 'PagerDutyNotifierFailed' });
   204→      await super.handle(message);
   205→    }
   206→  }
   207→}
   208→
   209→class FallbackLoggerHandler extends AbstractHandler {
   210→  constructor(private readonly logger: Logger) { super(); }
   211→  async handle(message: string): Promise<void> {
   212→    this.logger.warn({ msg: 'FallbackLogger', message });
   213→    await super.handle(message);
   214→  }
   215→}
   216→
   217→/* ============================ Auto-Scaler Service =================================== */
   218→
   219→export class SocialAwareAutoScaler {
   220→  private readonly kafka: Kafka;
   221→  private readonly kafkaProducer: Producer;
   222→  private readonly natsConn: NatsConnection;
   223→  private readonly jc = JSONCodec();
   224→
   225→  private readonly logger: Logger;
   226→  private readonly strategy: ScalingStrategy;
   227→
   228→  private slackHandler: AlertHandler;
   229→
   230→  constructor(
   231→    private readonly kafkaBrokers: string[],
   232→    private readonly natsUrl: string,
   233→    strategy?: ScalingStrategy
   234→  ) {
   235→    this.logger = pino({ name: 'SocialAwareAutoScaler' });
   236→    this.kafka = new Kafka({ clientId: 'auto-scaler', brokers: kafkaBrokers });
   237→    this.kafkaProducer = this.kafka.producer();
   238→    this.strategy = strategy ?? new HybridStrategy(
   239→      new SocialTrendingStrategy(),
   240→      new CpuLoadStrategy()
   241→    );
   242→    this.natsConn = {} as any; // will connect later
   243→
   244→    // Alert pipeline
   245→    this.slackHandler = new SlackNotifierHandler(this.logger);
   246→    this.slackHandler
   247→      .setNext(new PagerDutyHandler(this.logger))
   248→      .setNext(new FallbackLoggerHandler(this.logger));
   249→  }
   250→
   251→  /* ---------- Bootstrapping ---------- */
   252→
   253→  async start(): Promise<void> {
   254→    try {
   255→      await this.kafkaProducer.connect();
   256→      this.logger.info('Kafka producer connected');
   257→
   258→      // Connect to NATS
   259→      this.natsConn = await natsConnect({ servers: this.natsUrl });
   260→      this.logger.info('NATS connected');
   261→
   262→      // Subscribe to streams
   263→      await this.subscribeSystemMetrics();
   264→      await this.subscribeSocialSignals();
   265→
   266→      this.logger.info(`Auto-Scaler started with strategy ${this.strategy.name}`);
   267→    } catch (err) {
   268→      this.logger.fatal({ err }, 'Failed to start Auto-Scaler');
   269→      process.exit(1);
   270→    }
   271→  }
   272→
   273→  async shutdown(): Promise<void> {
   274→    await Promise.allSettled([this.kafkaProducer.disconnect(), this.natsConn.close()]);
   275→    this.logger.info('Graceful shutdown complete.');
   276→  }
   277→
   278→  /* ---------- Internal Subscription Logic ---------- */
   279→
   280→  private async subscribeSystemMetrics(): Promise<void> {
   281→    const consumer = this.kafka.consumer({ groupId: 'auto-scaler-group' });
   282→    await consumer.connect();
   283→    await consumer.subscribe({ topic: 'telemetry.system', fromBeginning: false });
   284→
   285→    consumer.run({
   286→      eachMessage: async (payload: EachMessagePayload) => {
   287→        try {
   288→          const metric: SystemMetric = JSON.parse(payload.message.value!.toString());
   289→
   290→          // Merge with any cached social signal if available
   291→          const combined: CombinedMetrics = { system: metric, social: this.lastSocialSignal };
   292→
   293→          await this.maybeScale(combined);
   294→        } catch (err) {
   295→          this.logger.error({ err }, 'Failed to handle system metric message');
   296→        }
   297→      }
   298→    });
   299→  }
   300→
   301→  private lastSocialSignal?: SocialSignal;
   302→  private async subscribeSocialSignals(): Promise<void> {
   303→    const sub: Subscription = this.natsConn.subscribe('social.trending');
   304→    (async () => {
   305→      for await (const msg of sub) {
   306→        try {
   307→          const signal: SocialSignal = this.jc.decode(msg.data);
   308→          this.lastSocialSignal = signal; // simple cache
   309→          const dummySystem: SystemMetric = {
   310→            timestamp: signal.timestamp,
   311→            instanceId: 'social-only',
   312→            cpuLoadPct: 0,
   313→            memoryLoadPct: 0
   314→          };
   315→          await this.maybeScale({ system: dummySystem, social: signal });
   316→
   317→        } catch (err) {
   318→          this.logger.error({ err }, 'Failed to handle social signal message');
   319→        }
   320→      }
   321→    })().catch(err => this.logger.error({ err }, 'NATS subscription failed'));
   322→  }
   323→
   324→  /* ---------- Core Decision Loop ---------- */
   325→
   326→  private async maybeScale(input: CombinedMetrics): Promise<void> {
   327→    const cmd = this.strategy.evaluate(input);
   328→    if (cmd) {
   329→      this.logger.info({ cmd }, 'Scaling decision issued');
   330→
   331→      try {
   332→        await this.kafkaProducer.send({
   333→          topic: 'orchestration.scaling.command',
   334→          messages: [{ key: cmd.targetGroup, value: JSON.stringify(cmd) }]
   335→        });
   336→      } catch (err) {
   337→        this.logger.error({ err }, 'Failed to publish scaling command');
   338→        await this.slackHandler.handle(`Scaling command failed: ${err}`);
   339→      }
   340→    }
   341→  }
   342→}
   343→
   344→/* ============================= Run if main ========================================== */
   345→
   346→if (require.main === module) {
   347→  const scaler = new SocialAwareAutoScaler(
   348→    process.env.KAFKA_BROKERS?.split(',') ?? ['localhost:9092'],
   349→    process.env.NATS_URL ?? 'nats://127.0.0.1:4222'
   350→  );
   351→
   352→  scaler.start();
   353→
   354→  // Graceful shutdown
   355→  process.on('SIGINT', async () => {
   356→    await scaler.shutdown();
   357→    process.exit(0);
   358→  });
   359→}
   360→```

