   104→/**
   105→ * Defines contract for a capacity scaling algorithm
   106→ */
   107→interface ScalingStrategy {
   108→  name: string;
   109→  assess(signal: CorrelatedSignal): Promise<ScalingDecision>;
   110→}
   111→
   112→/**
   113→ * Baseline strategy: HorizontalPodAutoscaler-like rule engine
   114→ */
   115→class HPAStrategy implements ScalingStrategy {
   116→  public readonly name = 'hpa';
   117→
   118→  constructor(
   119→    private minReplicas: number,
   120→    private maxReplicas: number,
   121→    private rpsPerReplica: number,
   122→  ) {}
   123→
   124→  async assess(signal: CorrelatedSignal): Promise<ScalingDecision> {
   125→    const { projectedRPS } = signal;
   126→    const desired = Math.ceil(projectedRPS / this.rpsPerReplica);
   127→
   128→    if (desired <= this.minReplicas) {
   129→      return { desiredReplicas: this.minReplicas, rationale: 'Within min bounds' };
   130→    }
   131→    if (desired >= this.maxReplicas) {
   132→      return {
   133→        desiredReplicas: this.maxReplicas,
   134→        rationale: 'Capped at max replicas',
   135→      };
   136→    }
   137→    return { desiredReplicas: desired, rationale: 'Scaled linearly against RPS' };
   138→  }
   139→}
