   141→/**
   142→ * Cost-aware custom strategy which chooses between spot and on-demand nodes
   143→ */
   144→class CostOptimizedStrategy implements ScalingStrategy {
   145→  public readonly name = 'cost_optimized';
   146→
   147→  constructor(private baseline: HPAStrategy, private costPerReplica: number) {}
   148→
   149→  async assess(signal: CorrelatedSignal): Promise<ScalingDecision> {
   150→    const base = await this.baseline.assess(signal);
   151→    if (base.desiredReplicas === null) {
   152→      return base;
   153→    }
   154→    const cost = base.desiredReplicas * this.costPerReplica;
   155→    return {
   156→      ...base,
   157→      expectedCostUSD: cost,
   158→      rationale: `${base.rationale}. Estimated cost $${cost.toFixed(2)}`,
   159→    };
   160→  }
   161→}
