   166→
   167→/**
   168→ * Abstract handler capable of executing/handling remediation action
   169→ */
   170→abstract class RemediationHandler {
   171→  private nextHandler: RemediationHandler | null = null;
   172→
   173→  setNext(next: RemediationHandler): RemediationHandler {
   174→    this.nextHandler = next;
   175→    return next;
   176→  }
   177→
   178→  async handle(signal: CorrelatedSignal, decision: ScalingDecision): Promise<void> {
   179→    try {
   180→      const handled = await this.process(signal, decision);
   181→      if (!handled && this.nextHandler) {
   182→        await this.nextHandler.handle(signal, decision);
   183→      }
   184→    } catch (err) {
   185→      logger.error(err, 'Remediation handler threw error');
   186→      bus.emit(InternalBus.EVENTS.REMEDIATION_FAILED, err);
   187→      if (this.nextHandler) {
   188→        await this.nextHandler.handle(signal, decision);
   189→      }
   190→    }
   191→  }
   192→
   193→  protected abstract process(
   194→    signal: CorrelatedSignal,
   195→    decision: ScalingDecision,
   196→  ): Promise<boolean>;
   197→}
