   211→    if (decision.desiredReplicas === null) return false;
   212→
   213→    logger.info(
   214→      { deployment: this.deployment, replicas: decision.desiredReplicas },
   215→      'Scaling deployment',
   216→    );
   217→
   218→    // Safeguard: avoid flapping
   219→    const current = await this.kubeClient.getReplicaCount(this.deployment);
   220→    if (current === decision.desiredReplicas) {
   221→      logger.debug('Desired replica count already satisfied; skipping scale action.');
   222→      return true;
   223→    }
   224→
   225→    await this.kubeClient.scaleDeployment(this.deployment, decision.desiredReplicas);
