   323→  async stop(): Promise<void> {
   324→    await this.consumer.disconnect();
   325→    logger.info('Virality correlator service stopped.');
   326→  }
   327→
   328→  /* ---------------------------- Private Helpers --------------------------- */
   329→
   330→  /**
   331→   * Parse and process each message coming from Kafka.
   332→   */
   333→  private async handleMessage({ message }: EachMessagePayload): Promise<void> {
   334→    if (!message.value) return;
   335→    const raw: SocialMetricEvent = JSON.parse(message.value.toString());
   336→
   337→    const correlated = this.enrich(raw);
   338→    if (correlated.viralityScore < 0.7) {
   339→      // below threshold – ignore to reduce noise
   340→      return;
   341→    }
   342→
   343→    bus.emit(InternalBus.EVENTS.VIRALITY_DETECTED, correlated);
   344→    logger.debug({ correlated }, 'Virality detected');
   345→
   346→    const decision = await this.strategy.assess(correlated);
   347→    bus.emit(InternalBus.EVENTS.SCALE_DECISION, decision);
   348→    logger.info({ decision }, 'Scaling decision generated');
   349→
   350→    await this.remediationChain.handle(correlated, decision);
   351→  }
   352→
   353→  /**
   354→   * Enrichment algorithm – a simplistic scoring heuristic
   355→   */
   356→  private enrich(event: SocialMetricEvent): CorrelatedSignal {
   357→    const { likes, comments, shares, viewers } = event;
   358→
   359→    // Weighted sum, tuned offline with historical data
   360→    const viralityScore =
   361→      0.4 * this.norm(likes) + 0.3 * this.norm(comments) + 0.2 * this.norm(shares) + 0.1 * this.norm(viewers);
   362→
   363→    // Convert virality score to projected RPS using linear regression coefficients
   364→    const projectedRPS = Math.round(viralityScore * 1500); // 1.0 ≈ 1500rps
   365→
   366→    return { viralityScore, projectedRPS };
   367→  }
   368→
   369→  /**
   370→   * Normalize raw counter via log scale to squish heavy tails
   371→   */
   372→  private norm(value: number): number {
   373→    if (value <= 0) return 0;
   374→    return Math.min(1, Math.log10(value + 1) / 4); // log10(10k) ~= 4
   375→  }
   376→
   377→  private handleError(err: unknown): void {
   378→    logger.error(err, 'Error while processing Kafka message');
   379→  }
   380→}
