    33→
    34→/* ------------------------------------------------------------------ */
    35→/*                                Types                               */
    36→/* ------------------------------------------------------------------ */
    37→
    38→/**
    39→ * Raw, enriched telemetry event.
    40→ */
    41→export interface MetricEvent {
    42→  service: string; // e.g. "timeline-api"
    43→  host: string; // e.g. "ip-10-2-3-4"
    44→  timestamp: number; // epoch millis
    45→  metrics: {
    46→    cpuUtilization: number; // 0–1
    47→    memoryUtilization: number; // 0–1
    48→    p95LatencyMs: number;
    49→    requestRateRps: number;
    50→  };
    51→  socialSignals: {
    52→    likes: number;
    53→    comments: number;
    54→    shares: number;
    55→    liveStreamViewers: number;
    56→  };
    57→  tags?: Record<string, string>;
    58→}
    59→
    60→/**
    61→ * Anomaly detection result.
    62→ */
    63→export interface DetectionResult {
    64→  isAnomaly: boolean;
    65→  severity: Severity;
    66→  reason: string;
    67→  strategy: string;
    68→}
    69→
    70→export enum Severity {
    71→  Low = 'low',
    72→  Medium = 'medium',
    73→  High = 'high',
    74→  Critical = 'critical',
    75→}
    76→
    77→/* ------------------------------------------------------------------ */
    78→/*                         Strategy Pattern                           */
    79→/* ------------------------------------------------------------------ */
    80→
    81→/**
    82→ * Pluggable detection strategy contract.
    83→ */
    84→export interface DetectionStrategy {
    85→  readonly name: string;
    86→  detect(event: MetricEvent): DetectionResult | null;
    87→}
    88→
    89→/**
    90→ * CPU Spike strategy – identifies sudden CPU utilisation > 85%.
    91→ */
    92→export class CpuSpikeStrategy implements DetectionStrategy {
    93→  readonly name = 'cpu_spike';
    94→
    95→  detect(event: MetricEvent): DetectionResult | null {
    96→    const { cpuUtilization } = event.metrics;
    97→    if (cpuUtilization > 0.85) {
    98→      return {
    99→        isAnomaly: true,
   100→        severity: cpuUtilization > 0.95 ? Severity.Critical : Severity.High,
   101→        reason: `CPU utilisation at ${(cpuUtilization * 100).toFixed(2)}%`,
   102→        strategy: this.name,
   103→      };
   104→    }
   105→    return null;
   106→  }
   107→}
   108→
   109→/**
   110→ * Memory Leak strategy – memory > 90%.
