   112→export class MemoryLeakStrategy implements DetectionStrategy {
   113→  readonly name = 'memory_leak';
   114→
   115→  detect(event: MetricEvent): DetectionResult | null {
   116→    const { memoryUtilization } = event.metrics;
   117→    if (memoryUtilization > 0.9) {
