   132→/**
   133→ * Viral Surge strategy – sudden user interest (shares + likes) combined
   134→ * with rising latency.
   135→ */
   136→export class ViralSurgeStrategy implements DetectionStrategy {
   137→  readonly name = 'viral_surge';
   138→
   139→  private readonly SOCIAL_THRESHOLD = 10_000; // customizable
   140→
   141→  detect(event: MetricEvent): DetectionResult | null {
   142→    const socialScore =
   143→      event.socialSignals.likes +
   144→      event.socialSignals.comments +
   145→      event.socialSignals.shares +
   146→      event.socialSignals.liveStreamViewers;
   147→
   148→    if (
   149→      socialScore > this.SOCIAL_THRESHOLD &&
