   151→    ) {
   152→      return {
   153→        isAnomaly: true,
   154→        severity:
   155→          socialScore > this.SOCIAL_THRESHOLD * 2
   156→            ? Severity.Critical
   157→            : Severity.Medium,
   158→        reason: `Viral surge detected (${socialScore} interactions) with latency ${
   159→          event.metrics.p95LatencyMs
   160→        } ms`,
   161→        strategy: this.name,
   162→      };
   163→    }
   164→    return null;
   165→  }
   166→}
