   168→/**
   169→ * Strategy registry allowing dynamic plug-in/out at runtime.
   170→ */
   171→export class StrategyRegistry {
   172→  private readonly strategies = new Map<string, DetectionStrategy>();
   173→
   174→  register(strategy: DetectionStrategy) {
   175→    if (this.strategies.has(strategy.name)) {
   176→      logger.warn({ strategy: strategy.name }, 'Strategy already registered');
   177→      return;
   178→    }
   179→    this.strategies.set(strategy.name, strategy);
   180→    logger.info({ strategy: strategy.name }, 'Strategy registered');
   181→  }
   182→
   183→  unregister(name: string) {
   184→    this.strategies.delete(name);
   185→    logger.info({ name }, 'Strategy unregistered');
   186→  }
   187→
   188→  detect(event: MetricEvent): DetectionResult[] {
   189→    const results: DetectionResult[] = [];
   190→    for (const strategy of this.strategies.values()) {
   191→      try {
   192→        const result = strategy.detect(event);
   193→        if (result?.isAnomaly) results.push(result);
   194→      } catch (err) {
   195→        logger.error(
   196→          { err, strategy: strategy.name },
   197→          'Strategy execution error',
   198→        );
   199→      }
   200→    }
   201→    return results;
   202→  }
   203→}
