   205→/* ------------------------------------------------------------------ */
   206→/*                          Observer Pattern                          */
   207→/* ------------------------------------------------------------------ */
   208→
   209→export interface AnomalyEvent {
   210→  metric: MetricEvent;
   211→  detections: DetectionResult[];
   212→}
   213→
   214→export type AnomalyListener = (anomaly: AnomalyEvent) => void;
   215→
   216→/**
