   230→  evaluate(event: MetricEvent): void {
   231→    const detections = this.registry.detect(event);
   232→    if (detections.length) {
   233→      const anomaly: AnomalyEvent = { metric: event, detections };
   234→      this.emit('anomaly', anomaly);
