   247→/* ------------------------------------------------------------------ */
   248→/*                  Chain-of-Responsibility: Escalation               */
   249→/* ------------------------------------------------------------------ */
   250→
   251→export interface EscalationContext {
   252→  anomaly: AnomalyEvent;
   253→}
   254→
   255→export abstract class EscalationHandler {
   256→  private next?: EscalationHandler;
   257→
   258→  setNext(next: EscalationHandler): EscalationHandler {
   259→    this.next = next;
   260→    return next;
