   273→
   274→  /**
   275→   * Return true if the handler fully handled the anomaly (no further
   276→   * escalation needed).
   277→   */
   278→  protected abstract process(ctx: EscalationContext): Promise<boolean>;
   279→}
   280→
   281→/**
   282→ * AutoScaler handler – tries to resolve by adding capacity.
