    90→
    91→/* -------------------------------------------------------------------------- */
    92→/*                           🔁 Exponential Backoff                           */
    93→/* -------------------------------------------------------------------------- */
    94→
    95→export interface RetryOptions {
    96→  retries: number;            // Total retry attempts (excluding the initial try)
    97→  factor?: number;            // Exponential factor (default = 2)
    98→  minTimeout?: number;        // Initial delay in ms
    99→  maxTimeout?: number;        // Max cap delay in ms
   100→  jitter?: boolean;           // Add random jitter to each delay
   101→  abortSignal?: AbortSignal;  // Allows external cancellation
   102→  onRetry?: (
   103→    attempt: number,
   104→    error: unknown,
   105→    delay: number,
   106→  ) => void | Promise<void>;  // Hook executed before each retry sleep
   107→}
   108→
   109→const DEFAULT_RETRY_OPTS: Omit<RetryOptions, 'retries'> = {
