   125→    retries,
   126→    factor,
   127→    minTimeout,
   128→    maxTimeout,
   129→    jitter,
   130→    abortSignal,
   131→    onRetry,
   132→  }: RetryOptions,
   133→): Promise<T> {
   134→  // merge defaults
   135→  factor = factor ?? DEFAULT_RETRY_OPTS.factor;
   136→  minTimeout = minTimeout ?? DEFAULT_RETRY_OPTS.minTimeout;
   137→  maxTimeout = maxTimeout ?? DEFAULT_RETRY_OPTS.maxTimeout;
   138→  jitter = jitter ?? DEFAULT_RETRY_OPTS.jitter;
