   140→  let attempt = 0;
   141→  let lastErr: unknown;
   142→
   143→  // Use for-loop for more explicitness
   144→  for (; attempt <= retries; attempt++) {
   145→    if (abortSignal?.aborted) {
   146→      throw new Error('Retry aborted by AbortSignal.');
   147→    }
   148→
   149→    try {
   150→      return await task();
