   240→/* -------------------------------------------------------------------------- */
   241→/*                           🗑️  Expiry-Aware Cache                           */
   242→/* -------------------------------------------------------------------------- */
   243→
   244→/**
   245→ * A minimal in-memory cache with TTL semantics.
   246→ *
   247→ * NOT suitable for cross-process caching but works well for holding
   248→ * ephemeral lookups such as recently seen message IDs or feature flags.
   249→ */
   250→export class TTLCache<K, V> {
   251→  private readonly store = new Map<K, { value: V; expires: number }>();
   252→
   253→  constructor(private readonly defaultTtlMs = 60_000) {}
   254→
   255→  /**
   256→   * Get value if not expired.
   257→   */
   258→  get(key: K): V | undefined {
   259→    const entry = this.store.get(key);
   260→    if (!entry) return undefined;
   261→
   262→    if (Date.now() > entry.expires) {
   263→      this.store.delete(key);
   264→      return undefined;
   265→    }
   266→    return entry.value;
