   269→  /**
   270→   * Insert or update.
   271→   */
   272→  set(key: K, value: V, ttlMs = this.defaultTtlMs): void {
   273→    const expires = Date.now() + ttlMs;
   274→    this.store.set(key, { value, expires });
   275→  }
   276→
   277→  /**
   278→   * Delete entry.
   279→   */
   280→  delete(key: K): boolean {
   281→    return this.store.delete(key);
   282→  }
   283→
   284→  /**
   285→   * Remove all expired items.  Can be called periodically via setInterval.
   286→   */
   287→  sweep(): void {
   288→    const now = Date.now();
   289→    for (const [k, { expires }] of this.store) {
   290→      if (now > expires) this.store.delete(k);
   291→    }
   292→  }
   293→
   294→  /**
   295→   * Number of items (both expired and active).  Expired items are removed first.
   296→   */
   297→  size(): number {
   298→    this.sweep();
   299→    return this.store.size;
   300→  }
   301→}
